// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: SINGLE ICON
// COMPANY: DISCOVER TECHNOLOGIES
// 2.8   | 2022-06-01 | raj  | STRY0121339 - Homepage UI Update- New Design for Colorful Filter and "Show More Filters" dropdown
//                                         New widget for home page
//
//------------------------------------------------------------------------------------------------------------------------
(function ($sp, input, data, options, gs) {
	main();

	function main(){
		// populate the 'data' variable provided by the caller
		data.items = $sp.getMenuItems($sp.getValue("sys_id"));

		var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('tasker_home_icon');
		data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
		data.messages = taskWidgetIconsAndMessage.loadMessages();
		data.icons = taskWidgetIconsAndMessage.loadIcons();

		data.homeURL = data.settings.baseURL + data.settings.service_portal_url_suffix;

	}
})($sp, input, data, options, gs);
